#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int count = 0;
        for (int a = 1; a <= N / 2; a++) {
            int d = N - a;
            for (int b = 1; b < a * d; b++) {
                if (a * d % b == 0) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

