import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int count = 0;
            for (int a = 1; a <= N / 2; a++) {
                int d = N - a;
                for (int b = 1; b < a * d; b++) {
                    if (a * d % b == 0) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

